const{SlashCommandBuilder:SlashCommandBuilder,EmbedBuilder:EmbedBuilder}=require("discord.js"),fetch=require("node-fetch"),config=require("../config");class CollectionPnlCommand{constructor(){}getCommandData(){return(new SlashCommandBuilder).setName("collectionpnl").setDescription("Compute realized PnL for a wallet in a specific collection").addStringOption((option=>option.setName("wallet").setDescription("Wallet address (0x...)").setRequired(!0))).addStringOption((option=>option.setName("slug").setDescription("Collection slug (e.g. nightglyders)").setRequired(!0))).addStringOption((option=>option.setName("chain").setDescription("Blockchain network").setRequired(!1).addChoices({name:"Ethereum",value:"ethereum"},{name:"ApeChain",value:"ape_chain"},{name:"Base",value:"base"},{name:"Polygon",value:"polygon"},{name:"Arbitrum",value:"arbitrum"},{name:"Optimism",value:"optimism"})))}lower(x){return(x||"").toLowerCase()}getContractFromEvent(evt){return this.lower(evt?.nft?.contract||evt?.contract||evt?.asset?.asset_contract?.address||evt?.asset?.contract_address||"")}getTokenIdFromEvent(evt){const id=evt?.nft?.identifier??evt?.asset?.token_id??evt?.token_id??evt?.item?.nft_id?.split("/")?.pop();return null!=id?String(id):""}getSellerFromEvent(evt){return this.lower(evt?.seller?.address||evt?.from_account?.address||evt?.sender?.address||"")}getBuyerFromEvent(evt){return this.lower(evt?.buyer?.address||evt?.to_account?.address||evt?.recipient?.address||"")}parsePayment(evt){let native=0,usd=0;if(evt?.payment?.quantity){const dec=Number(evt?.payment?.decimals??18);return native=Number(evt.payment.quantity)/10**dec,usd=Number(evt?.payment?.usd_amount??0),{native:native,usd:usd}}if(null!=evt?.sale_price){const dec=Number(evt?.payment_token?.decimals??18);return native=Number(evt.sale_price)/10**dec,usd=Number(evt?.payment?.usd_amount??0),{native:native,usd:usd}}if(null!=evt?.price?.value){const dec=Number(evt?.price?.currency?.decimals??18);return native=Number(evt.price.value)/10**dec,usd=Number(evt?.price?.currency?.usd_price??0)*native||0,{native:native,usd:usd}}return{native:0,usd:0}}async fetchAllAccountEvents({wallet:wallet,chain:chain,after:after,apiKey:apiKey}){let cursor=null;const out=[];for(;;){const params=new URLSearchParams({limit:"100",occurred_after:String(after),chain:chain});["sale","mint","bid_accepted"].forEach((t=>params.append("event_type",t))),cursor&&params.set("cursor",cursor);const url=`https://api.opensea.io/api/v2/events/accounts/${wallet}?${params.toString()}`;console.log(`🔗 Fetching events: ${url}`);const res=await fetch(url,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(!res.ok)throw new Error(`Events fetch failed: ${res.status} ${await res.text()}`);const json=await res.json(),arr=Array.isArray(json.asset_events)?json.asset_events:Array.isArray(json.events)?json.events:[];if(console.log(`📊 Fetched ${arr.length} events, cursor: ${cursor}`),out.push(...arr),cursor=json.next||json.next_cursor||null,!cursor)break}return out}async execute(interaction){try{await interaction.deferReply();const wallet=interaction.options.getString("wallet",!0).toLowerCase(),slug=interaction.options.getString("slug",!0),chain=interaction.options.getString("chain")||"ethereum",openSeaChain={ethereum:"ethereum",ape_chain:"ape_chain",base:"base",polygon:"polygon",arbitrum:"arbitrum",optimism:"optimism"}[chain]||chain;console.log(`🔍 /collectionpnl for wallet ${wallet}, slug ${slug} on ${chain} (OpenSea: ${openSeaChain})`);const nftTracker=new(require("./nftTracker")),collectionInfo=await nftTracker.getCollectionInfoBySlug(slug,chain),apiKey=config.opensea.apiKey,occurredAfter=Math.floor((Date.now()-31536e6)/1e3);let events;try{events=await this.fetchAllAccountEvents({wallet:wallet,chain:openSeaChain,after:occurredAfter,apiKey:apiKey})}catch(e){return void await interaction.editReply({content:`❌ Failed to fetch account events: ${e.message}`})}console.log(`📊 Total events fetched: ${events.length}`);const contracts=Array.isArray(collectionInfo?.contracts)?collectionInfo.contracts.filter((c=>{const ch=this.lower(c?.chain);return!ch||ch===this.lower(openSeaChain)})).map((c=>this.lower(c?.address))).filter(Boolean):[];if(console.log(`🔗 Collection contracts: ${contracts.join(", ")}`),0===contracts.length)return void await interaction.editReply({content:"❌ No contracts found for this collection on selected chain."});const saleEvents=events.filter((evt=>{const contractAddr=this.getContractFromEvent(evt),seller=this.getSellerFromEvent(evt);return contractAddr&&contracts.includes(contractAddr)&&seller===wallet}));console.log(`💰 Sale events found: ${saleEvents.length}`);let totalPnL=0,totalPnLUSD=0,realizedSales=0,totalBuy=0,totalSell=0;const rows=[];for(const evt of saleEvents)try{const{native:salePrice,usd:salePriceUSD}=this.parsePayment(evt);if(!Number.isFinite(salePrice)||salePrice<=0){console.log(`⚠️ Skipping event with invalid price: ${JSON.stringify(evt,null,2)}`);continue}const contractAddress=this.getContractFromEvent(evt),tokenId=this.getTokenIdFromEvent(evt);console.log(`🔍 Recovering purchase data for ${contractAddress} #${tokenId}`);const purchase=await nftTracker.recoverPurchaseData(contractAddress,tokenId,wallet,openSeaChain);if(!purchase||!Number.isFinite(purchase.price)){console.log(`⚠️ No purchase data found for ${contractAddress} #${tokenId}`);continue}const pnl=salePrice-purchase.price,pnlUSD=(salePriceUSD||0)-(purchase.priceUSD||0);totalPnL+=pnl,totalPnLUSD+=pnlUSD,realizedSales+=1,totalBuy+=purchase.price,totalSell+=salePrice,rows.push({tokenId:tokenId,buy:purchase.price,sell:salePrice,pnl:pnl}),console.log(`✅ PnL calculated: ${pnl} (buy: ${purchase.price}, sell: ${salePrice})`)}catch(e){console.error("❌ Error processing event:",e);continue}const nativeSymbol=nftTracker.getNativeTokenSymbol(openSeaChain),embed=(new EmbedBuilder).setTitle(`📈 PnL for ${slug}`).setColor(49151).addFields({name:"👛 Wallet",value:wallet,inline:!1},{name:"🔷 Chain",value:chain.toUpperCase(),inline:!0},{name:"🧾 Sales Count",value:String(realizedSales),inline:!0},{name:"💰 Total Buy",value:`${totalBuy.toFixed(4)} ${nativeSymbol}`,inline:!0},{name:"💵 Total Sell",value:`${totalSell.toFixed(4)} ${nativeSymbol}`,inline:!0},{name:"📊 Realized PnL",value:`${totalPnL>=0?"+":""}${totalPnL.toFixed(4)} ${nativeSymbol}`,inline:!0},{name:"⚠️ Note",value:"PnL calculation does not include gas fees, platform fees, or other transaction costs.",inline:!1}).setFooter({text:"⚡ Powered by STPNGPT • /collectionpnl"}).setTimestamp();if(collectionInfo?.stats){const stats=collectionInfo.stats,floorPrice=stats.floor_price?`${stats.floor_price} ${nativeSymbol}`:"—",totalVolume=stats.total_volume?`${stats.total_volume} ${nativeSymbol}`:"—";embed.addFields({name:"🏠 Floor Price",value:floorPrice,inline:!0},{name:"📈 Total Volume",value:totalVolume,inline:!0})}if(rows.length>0){rows.sort(((a,b)=>b.pnl-a.pnl));const top=rows.slice(0,5).map((r=>`#${r.tokenId}: ${r.pnl>=0?"+":""}${r.pnl.toFixed(4)} ${nativeSymbol}`)).join("\n"),bottom=rows.slice(-5).reverse().map((r=>`#${r.tokenId}: ${r.pnl>=0?"+":""}${r.pnl.toFixed(4)} ${nativeSymbol}`)).join("\n");embed.addFields({name:"🏆 Top PnL",value:top||"—",inline:!1},{name:"⚠️ Worst PnL",value:bottom||"—",inline:!1})}await interaction.editReply({embeds:[embed]})}catch(error){console.error("❌ Error in collectionpnl command:",error);const errorMessage="❌ An error occurred while calculating PnL.";try{interaction.deferred?await interaction.editReply({content:errorMessage}):await interaction.reply({content:errorMessage,ephemeral:!0})}catch(_){}}}}module.exports=CollectionPnlCommand;